class Solution {
public:
    int totalNQueens(int n) {
        int count = 0;
        std::function<void(int, std::vector<int>, std::vector<int>)> backtrack =
            [&](int row, std::vector<int> column, std::vector<int> diagonal) {
                if (row == n) {
                    count++;
                    return;
                }
                for (int col = 0; col < n; col++) {
                    if (column[col] == col && diagonal[col - row] == col - row && diagonal[n - 1 + col + row] == n - 1 + col + row) {
                        column[col] = col;
                        diagonal[col - row] = col - row;
                        diagonal[n - 1 + col + row] = n - 1 + col + row;
                        backtrack(row + 1, column, diagonal);
                        column[col] = 0;
                        diagonal[col - row] = 0;
                        diagonal[n - 1 + col + row] = 0;
                    }
                }
            };

        for (int row = 0; row < n; row++) {
            std::vector<int> column;
            for (int col = 0; col < n; col++) {
                column.push_back(col);
            }
            std::vector<int> diagonal;
            for (int i = 0; i < n; i++) {
                diagonal.push_back(i);
            }
            backtrack(row, column, diagonal);
        }

        return count;
    }
};
